See the code <pre><code>#include &lt;bits/stdc++.h&gt;
using namespace std;

class Node{

    public:
    int data;
    Node* left;
    Node* right;
    Node(int x){
        this -&gt;data = x;
        this -&gt;left = NULL;
        this -&gt;right = NULL;
    }
};

Node* Construct_tree(vector&lt;int&gt; arr){

    if(arr.empty()){
        return NULL;
    }

    queue&lt;Node*&gt; q;
    int index = 1;

    Node* root = new Node(arr[0]);
    q.push(root);

    while(!q.empty()){

        Node* t = q.front();
        q.pop();

        if(index &lt; arr.size() &amp;&amp; arr[index] != -1){
            Node* ln = new Node(arr[index]);
            t -&gt;left = ln;
            q.push(t -&gt;left);
        }
        index++;

        if(index &lt; arr.size() &amp;&amp; arr[index] != -1){
            Node* rn = new Node(arr[index]);
            t -&gt;right = rn;
            q.push(t -&gt;right);
        }
        index++;
    }

    return root;
}

void display(Node* root){

    if(root == NULL){
        return;
    }

    string str = "";
    str += root -&gt;left == NULL ? "." : to_string(root -&gt;left -&gt;data) + "";
    str += "&lt;--" + to_string(root -&gt;data) + "--&gt;";
    str += root -&gt;right == NULL ? "." : to_string(root -&gt;right -&gt;data) + "";

    cout&lt;&lt;str&lt;&lt;endl;

    display(root -&gt;left);
    display(root -&gt;right);
}


int main(){

    vector&lt;int&gt; arr = {50, 25, 75, 12, 37, 62, 87, -1, -1, 30, -1, -1, 70, -1, -1};

    Node* root = Construct_tree(arr);
    display(root);

    cout&lt;&lt;endl;

}
