</code></pre></li> </ul> <pre><code>class Solution{
public:

    bool check(int start , vector&lt;int&gt; adj[] , vector&lt;int&gt; &amp;color){

        queue&lt;int&gt; q;
        q.push(start);
        color[start] = 0;

        while(!q.empty()){
            int node = q.front();
            q.pop();

            for(auto it : adj[node]){
                if(color[it] == -1){
                    q.push(it);
                    color[it] = 1-color[node];
                }
                else if(color[it] == color[node]){
                    return false;
                }
            }
        }

        return true;
    }

    bool isBipartite(int V, vector&lt;int&gt;adj[]){

        vector&lt;int&gt; color(V,-1);

        for(int i = 0 ; i &lt; V ; i++){
            if(color[i] == -1){
                bool ans = check(i , adj , color);
                if(ans == false){
                    return false;
                }
            }
        }

        return true;
    }

};
</code></pre>

Points to remember <p>We need to create an extra <code>vector&lt;int&gt; color(V,-1)</code> vector to keep track of colored nodes.</p> <pre><code>class Solution{
public:

    bool check(int start , int col , vector&lt;int&gt; adj[] , vector&lt;int&gt; &amp;color){

        color[start] = col;

        for(auto it : adj[start]){
            if(color[it] == -1){
                if(check(it , 1-col , adj , color) == false){
                    return false;
                } 
            }
            else if(color[it] == col){
                return false;
            }
        }

        return true;
    }

    bool isBipartite(int V, vector&lt;int&gt;adj[]){

        vector&lt;int&gt; color(V,-1);

        for(int i = 0 ; i &lt; V ; i++){
            if(color[i] == -1){
                bool ans = check(i , 0 , adj , color);
                if(ans == false){
                    return false;
                }
            }
        }

        return true;
    }

};
</code></pre>

Steps to remember <ol> <li>Find in-degree of all nodes and fill them in an array.</li> <li>Now take Queue data structure and add nodes that have in-degree is 0.</li> <li>Take the top/peek node from Queue, add this x to our answer.</li> <li>We'll apply some conditions to the BFS:<ul> <li>Now take neighbour nodes of popped nodes and reduce their in-degree by 1.</li> <li>if any of the popped element nodes's in-degree becomes 0, push it in to the queue.</li> </ul> </li> </ol> <pre><code>vector&lt;int&gt; topo(int N, vector&lt;int&gt; adj[]) {
    queue&lt;int&gt; q; 
    vector&lt;int&gt; indegree(N, 0); 
    for(int i = 0;i&lt;N;i++) {
        for(auto it: adj[i]) {
            indegree[it]++; 
        }
    }

    for(int i = 0;i&lt;N;i++) {
        if(indegree[i] == 0) {
            q.push(i); 
        }
    }
    vector&lt;int&gt; topo;
    while(!q.empty()) {
        int node = q.front(); 
        q.pop(); 
        topo.push_back(node);
        for(auto it : adj[node]) {
            indegree[it]--;
            if(indegree[it] == 0) {
                q.push(it); 
            }
        }
    }
    return topo;
}
</code></pre>

Steps to remember <ul> <li>Visited Vector - To store visit of each vertex</li> <li>Stack - To maintain the topo sort order.</li> </ul> <pre><code>void findTopoSort(int node, vector&lt;int&gt; &amp;vis, stack&lt;int&gt; &amp;st, vector&lt;int&gt; adj[]) {
    vis[node] = 1;

    for (auto it: adj[node]) {
      if (!vis[it]) {
        findTopoSort(it, vis, st, adj);
      }
    }
    st.push(node);
}

vector&lt;int&gt; topoSort(int N, vector&lt;int&gt; adj[]) {
    stack&lt;int&gt; st;
    vector&lt;int&gt; vis(N, 0);
    for (int i = 0; i &lt; N; i++) {
        if (vis[i] == 0) {
            findTopoSort(i, vis, st, adj);
        }
    }
    vector&lt;int&gt; topo;
    while (!st.empty()) {
        topo.push_back(st.top());
        st.pop();
    }

    return topo;
}
</code></pre>

See the code <pre><code>#include &lt;bits/stdc++.h&gt; 
using namespace std; 

// Structure of Node
class Node{ 
  public: 
    int data;
    Node* next;
    Node* pre;

    Node(int data){
        this -&gt;data = data;
        this -&gt;next = NULL;
        this -&gt;pre = NULL;
    }
}; 

Node* constructLL(vector&lt;int&gt;&amp; arr) {

    if(arr.size() == 0){
        return NULL;
    }

    Node *Head = new Node(arr[0]);
    Node *temp = Head;

    for(int i = 1 ; i &lt; arr.size() ; i++){
        Node* new_node = new Node(arr[i]);
        temp -&gt;next = new_node;
        new_node -&gt;pre = temp;
        temp = temp -&gt;next;
    }

    return Head;
}

void printList(Node* head){ 

    Node* temp = head;
    while (temp != NULL) { 

        cout &lt;&lt; temp-&gt;data &lt;&lt; " "; 
        temp = temp-&gt;next;
    } 
}

int main(){ 

    vector&lt;int&gt; arr = {1,2,3,4,5};

    Node *head = constructLL(arr);
    printList(head);
    cout&lt;&lt;endl;

    return 0; 
}
